document.getElementById("menuButton")?.addEventListener("click",()=>{document.documentElement.classList.toggle("menu-open")});const e=document.documentElement,s=localStorage.getItem("theme"),l=window.matchMedia("(prefers-color-scheme: light)").matches;s==="light"||!s&&l?(e.classList.add("light"),e.classList.remove("dark")):(e.classList.add("dark"),e.classList.remove("light"));document.getElementById("themeToggle")?.addEventListener("click",()=>{const t=e.classList.contains("dark");e.classList.toggle("dark",!t),e.classList.toggle("light",t),localStorage.setItem("theme",t?"light":"dark")});
